import { defineStore } from 'pinia'

export const useBackendInfoTempStore = defineStore('backendinfotemp', {
  state: () => ({
    product:{
        id:'',
        productName:'',
        productDesc:'',
        productPrice:'',
        productStock:'',
        category:'',
        productImg:'',
    },
    customer:{
        account:'',
        address:'',
        birth:'',
        email:'',
        fullName:'',
        id:'',
        lastLoginDate:'',
        phoneNumber:''
    },

    productId:''
  })
  ,
  actions: {
    saveProduct(product){
        this.product.id=product.id
        this.product.productName=product.productName,
        this.product.productDesc=product.productDesc,
        this.product.productPrice=product.productPrice,
        this.product.productStock=product.productStock,
        this.product.category=product.category,
        this.product.productImg=product.productImg
    },
    saveCustomer(customer){
      this.customer.account=customer.account
      this.customer.address=customer.address
      this.customer.birth=customer.birth
      this.customer.email=customer.email
      this.customer.fullName=customer.fullName    
      this.customer.id=customer.id
      this.customer.lastLoginDate=customer.lastLoginDate
      this.customer.phoneNumber='0'+customer.phoneNumber
    },
    saveProductId(productId){
      this.productId=productId
    }

    
  },
})